    font-size: 0.82rem;
    font-weight: 500;
    color: var(--text-muted);
    cursor: pointer;
    transition: color 0.15s ease, background-color 0.15s ease;
}
.so-reply-btn:hover {
    color: var(--accent-amber);
    background-color: rgba(212, 168, 83, 0.08);
}

.opinions-page-parent-container .so-card-wrapper {
    width: min(720px, 92%);
    margin: 0 auto;
}

/* ── Opinion Viewer (ov-) — kept for MyOpinions.jsx ── */
.ov-card {
    display: flex;
    flex-direction: column;
    width: 100%;
    background-color: var(--bg-card);
    border: 1px solid var(--border-card);
    border-radius: 14px;
    padding: 1.15rem;
    gap: 0.75rem;
    box-sizing: border-box;
    transition: box-shadow 0.25s ease;
    margin-bottom: 1rem;
}
.ov-card:hover {
    box-shadow: 0 4px 18px rgba(0, 0, 0, 0.06);
}

.ov-user-row {
    display: flex;
    align-items: center;
    gap: 0.45rem;
}
.ov-avatar {
    width: 32px;
    height: 32px;
    border-radius: 50%;
    object-fit: cover;
}
.ov-username {
    font-family: var(--font-ui);
    font-size: 0.82rem;
    font-weight: 600;
    color: var(--text-heading);
    cursor: pointer;
    transition: color 0.15s ease;
}
.ov-username:hover {
    color: var(--accent-amber);
    text-decoration: underline;
}
.ov-dot {
    color: var(--text-separator);
    font-size: 0.8rem;
    line-height: 1;
}
.ov-date {
    font-family: var(--font-ui);
    font-size: 0.75rem;
    color: var(--text-faint);
}

.ov-body {
    font-family: var(--font-serif);
    font-size: 0.92rem;
    line-height: 1.7;
    color: var(--text-body);
    cursor: pointer;
}

.ov-meta-bar {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding-top: 0.6rem;
    border-top: 1px solid var(--border-card);
}
.ov-reply-pill {
    display: inline-flex;
    align-items: center;
    gap: 0.3rem;
    background-color: var(--bg-pill);
    border-radius: 10px;
    padding: 0.2rem 0.6rem;
    font-family: var(--font-ui);
    font-size: 0.72rem;
    font-weight: 500;
    color: var(--accent-amber);
    cursor: pointer;
}
.ov-full-date {
    font-family: var(--font-ui);
    font-size: 0.7rem;
    color: var(--text-faint);
}

/* ── Opinion Viewer stats + divider ── */
.ov-stats-row {
    display: flex;
    align-items: center;
    gap: 0.45rem;
    padding-top: 0.35rem;
}
.ov-stats-row .ov-reply-count {
    font-family: var(--font-ui);
    font-size: 0.82rem;
    font-weight: 600;
    color: var(--text-heading);
}
.ov-stats-row .so-dot {
    color: var(--text-faint);
    font-size: 0.75rem;
}
.ov-stats-row .ov-full-date {
    font-size: 0.75rem;
}
.ov-divider {
    width: 100%;
    height: 1px;
    background-color: var(--border-card);
    margin: 0.35rem 0;
}

/* ── Reply composer (ov-composer) ── */
.ov-composer {
    display: flex;
    align-items: flex-start;
    gap: 0.55rem;
    padding-top: 0.35rem;
}
.ov-composer-input-wrap {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-width: 0;
}
.ov-reply-row {
    display: flex;
    align-items: flex-end;
    gap: 0.5rem;
    padding-top: 0.25rem;
}
.ov-reply-avatar {
    width: 28px;
    height: 28px;
    border-radius: 50%;
    object-fit: cover;
    flex-shrink: 0;
}
.ov-reply-input {
    flex: 1;
    min-height: 1.4rem;
    outline: none;
    border: none;
    border-bottom: 1px solid var(--border-card);
    background-color: transparent;
    font-family: var(--font-ui);
    font-size: 0.82rem;
    font-style: normal;
    color: var(--text-primary);
    padding-bottom: 0.25rem;
    resize: none;
    transition: border-color 0.2s ease;
}
.ov-reply-input::placeholder {
    color: var(--text-faint);
}
.ov-reply-input:focus {
    border-bottom: 1px solid var(--border-card);
}

.ov-composer-actions {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 0.6rem;
    overflow: hidden;
}
.ov-char-count {
    font-family: var(--font-ui);
    font-size: 0.7rem;
    font-weight: 500;
    color: var(--text-faint);
}

.ov-btn-row {
    display: flex;
    gap: 0.6rem;
    justify-content: flex-end;
    overflow: hidden;
}
.ov-btn-cancel {
    cursor: pointer;
    background-color: transparent;
    border: 1px solid var(--border-card);
    color: var(--text-primary);
    border-radius: 20px;
    padding: 0.35rem 1rem;
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 500;
    transition: background-color 0.15s ease;
}
.ov-btn-cancel:hover {
    background-color: var(--bg-hover);
}
.ov-btn-submit {
    cursor: pointer;
    border: none;
    padding: 0.35rem 1rem;
    border-radius: 20px;
    background-color: var(--accent-amber);
    color: #ffffff;
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 600;
    transition: opacity 0.15s ease;
}
.ov-btn-submit:hover {
    opacity: 0.88;
}
.ov-btn-submit.ov-btn-disabled {
    cursor: default;
    user-select: none;
    opacity: 0.45;
}

/* ── Reply Card (rc-) — Avatar-column thread ── */
.rc-thread {
    padding-left: calc(var(--depth, 0) * 1rem);
    width: 100%;
    box-sizing: border-box;
}

.rc-reply {
    display: flex;
    gap: 0.65rem;
    padding: 0.65rem 0;
}

.rc-avatar-col {
    display: flex;
    flex-direction: column;
    align-items: center;
    width: 32px;
    flex-shrink: 0;
}
.rc-connector {
    flex: 1;
    width: 2px;
    background-color: var(--border-card);
    border-radius: 1px;
    margin-top: 0.35rem;
    transition: background-color 0.2s ease;
}
.rc-reply:hover .rc-connector {
    background-color: var(--accent-amber);
}
.rc-connector--hidden {
    visibility: hidden;
}

.rc-content {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
    flex: 1;
    min-width: 0;
}

.rc-user-row {
    display: flex;
    align-items: center;
    gap: 0.35rem;
}
.rc-avatar {
    width: 22px;
    height: 22px;
    border-radius: 50%;
    object-fit: cover;
}
.rc-username {
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 600;
    color: var(--text-heading);
}
.rc-dot {
    color: var(--text-separator);
    font-size: 0.75rem;
    line-height: 1;
}
.rc-date {
    font-family: var(--font-ui);
    font-size: 0.7rem;
    color: var(--text-faint);
}

.rc-body {
    font-family: var(--font-serif);
    font-size: 0.85rem;
    line-height: 1.65;
    color: var(--text-body);
    overflow-wrap: anywhere;
    word-break: break-word;
    white-space: pre-wrap;
}

.rc-actions {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding-top: 0.15rem;
}
.rc-show-replies {
    cursor: pointer;
    background: none;
    border: none;
    padding: 0;
    font-family: var(--font-ui);
    font-size: 0.75rem;
    font-weight: 500;
    color: var(--accent-amber);
    transition: opacity 0.15s ease;
}
.rc-show-replies:hover {
    opacity: 0.8;
}
.rc-reply-btn {
    cursor: pointer;
    background: none;
    border: none;
    padding: 0;
    font-family: var(--font-ui);
    font-size: 0.75rem;
    font-weight: 500;
    color: var(--text-muted);
    transition: color 0.15s ease;
}
.rc-reply-btn:hover {
    color: var(--accent-amber);
}

.rc-inline-composer {
    display: flex;
    flex-direction: column;
    gap: 0.4rem;
    overflow: hidden;
    padding-top: 0.25rem;
}

.rc-load-more {
    display: inline-flex;
    align-items: center;
    cursor: pointer;
    background: none;
    border: none;
    padding: 0.35rem 0;
    margin-top: 0.25rem;
    margin-left: calc(32px + 0.65rem);
    font-family: var(--font-ui);
    font-size: 0.75rem;
    font-weight: 500;
    color: var(--accent-amber);
    transition: opacity 0.15s ease;
}
.rc-load-more:hover {
    opacity: 0.8;
}

@media(max-width: 480px){
    .visited-profile-opinion-content{
        font-weight: 400;
        font-size: 0.8rem;
    }
    .visited-profile-opinions-container{
        width: 95%;
        padding: 0.65rem;
        margin-bottom: 4rem;
        height: fit-content;
    }
    .opinions-page-parent-container {
        display: flex;
        flex-direction: column;
        justify-content: flex-start;
        align-items: center;
        width: 100%;
        top: 60px;
        height: 100dvh;
        gap: 0;
        padding: 1rem 0 0rem 0;
    }

    .oe-card {
        width: min(420px, 92%);
        border-radius: 10px;
    }
    .oe-header {
        padding: 0.7rem 0.85rem;
    }
    .oe-title {
        font-size: 0.82rem;
    }
    .oe-body {
        padding: 0.6rem 0.85rem;
    }
    .oe-textarea {
        min-height: 100px;
        font-size: 0.85rem;
    }
    .oe-footer {
        padding: 0.5rem 0.85rem 0.7rem 0.85rem;
    }
    .oe-save-btn {
        font-size: 0.72rem;
        padding: 0.3rem 0.9rem;
    }

    .so-card--parent {
        padding: 0.85rem;
        border-radius: 12px;
    }

    .opinions-page-parent-container .so-card-wrapper {
        width: 92%;
    }

    /* ── Sidebar Opinion Card mobile ── */
    .so-card-wrapper {
        width: 100%;
        padding: 0;
        margin-bottom: 0;
    }
    .so-avatar-outer {
        width: 30px;
        height: 30px;
    }
    .so-avatar-outer .so-avatar {
        width: 30px;
        height: 30px;
    }
    .so-avatar-outer.avatar-ring-legend,
    .so-avatar-outer.avatar-ring-og {
        display: flex;
        align-items: center;
        justify-content: center;
        width: auto;
        height: auto;
    }
    .so-avatar-outer.avatar-ring-legend .so-avatar,
    .so-avatar-outer.avatar-ring-og .so-avatar {
        width: 30px;
        height: 30px;
    }
    .so-card {
        padding: 0.75rem 0.6rem;
    }
    .so-avatar {
        width: 30px;
        height: 30px;
    }
    .so-username {
        font-size: 0.82rem;
        max-width: 120px;
        overflow: hidden;
        text-overflow: ellipsis;
        white-space: nowrap;
    }
    .so-body {
        font-size: 1rem;
        line-height: 1.35;
        margin-left: 0;
    }
    .so-action-row {
        margin-left: 0;
    }
    .so-reply-btn {
        font-size: 0.78rem;
    }

    /* ── Opinion Viewer mobile ── */
    .ov-card {
        border-radius: 10px;
        padding: 0.85rem;
        gap: 0.55rem;
    }
    .ov-avatar {
        width: 28px;
        height: 28px;
    }
    .ov-username {
        font-size: 0.78rem;
        max-width: 120px;
        overflow: hidden;
        text-overflow: ellipsis;
        white-space: nowrap;
    }
    .ov-body {
        font-size: 0.85rem;
        line-height: 1.6;
    }
    .ov-reply-avatar {
        width: 24px;
        height: 24px;
    }
    .ov-reply-input {
        font-size: 0.78rem;
    }
    .ov-btn-cancel,
    .ov-btn-submit {
        font-size: 0.72rem;
        padding: 0.3rem 0.8rem;
    }

    /* ── Reply Card mobile ── */
    .rc-reply {
        gap: 0.45rem;
    }
    .rc-thread {
        padding-left: calc(var(--depth, 0) * 0.5rem);
    }
    .rc-avatar-col {
        width: 24px;
    }
    .rc-avatar-col .so-avatar-outer {
        width: 24px;
        height: 24px;
    }
    .rc-avatar-col .so-avatar-outer .so-avatar {
        width: 24px;
        height: 24px;
    }
    .rc-avatar {
        width: 18px;
        height: 18px;
    }
    .rc-username {
        font-size: 0.72rem;
        max-width: 100px;
        overflow: hidden;
        text-overflow: ellipsis;
        white-space: nowrap;
    }
    .rc-body {
        font-size: 0.8rem;
    }
    .rc-show-replies,
    .rc-reply-btn {
        font-size: 0.68rem;
    }
    .rc-load-more {
        font-size: 0.7rem;
        margin-left: calc(24px + 0.65rem);
    }

    /* ── Write Opinion FAB mobile ── */
    .write-opinion-fab {
        right: 1.25rem;
        bottom: 6.5rem;
        width: 54px;
        height: 54px;
    }
}
@media(max-width: 432px){
    .oe-card {
        width: 92%;
    }

    .write-opinion-fab {
        right: 1rem;
        bottom: 6rem;
        width: 50px;
        height: 50px;
    }
}
